    const double Y2r = (A2r + B2i), Y2i = (A2i - B2r);
    const double Y6r = (A2r - B2i), Y6i = (A2i + B2r);
    const double t3r = (vnc * (B3r - B3i)), t3i = (vnc * (B3r + B3i));
